fun solve(points: Array<Array<Long>>, target: Array<Long>): Long {
    // Use List<Long> as the canonical representation for points to use them in a Set
    val initialSet = mutableSetOf<List<Long>>()
    for (p in points) {
        initialSet.add(p.toList())
    }

    val targetList = target.toList()

    // Check Generation 0
    if (initialSet.contains(targetList)) {
        return 0L
    }

    var currentPoints = initialSet
    var k = 0L

    // The maximum number of unique points is 7^3 = 343 (since coordinates are 0-6).
    // The loop must terminate quickly if the target is reachable or if stabilization occurs.
    while (true) {
        k++

        val previousPointsList = currentPoints.toList()
        val newPoints = mutableSetOf<List<Long>>()

        val pointArray = previousPointsList.toTypedArray()
        val n = pointArray.size

        if (n < 2) {
            // Cannot generate new points if fewer than 2 points exist.
            return -1L
        }

        // Generate new points by pairing distinct points from currentPoints
        for (i in 0 until n) {
            for (j in i + 1 until n) {
                val a = pointArray[i]
                val b = pointArray[j]

                // Calculate midpoint c = [floor((x1+x2)/2), ...]
                val c = mutableListOf<Long>()
                for (dim in 0..2) {
                    // Integer division performs floor for non-negative numbers
                    val sum = a[dim] + b[dim]
                    val mid = sum / 2
                    c.add(mid)
                }

                newPoints.add(c)
            }
        }

        // Check Target
        if (newPoints.contains(targetList)) {
            return k
        }

        // Check for stabilization
        val newlyAddedPoints = mutableSetOf<List<Long>>()
        for (p in newPoints) {
            if (!currentPoints.contains(p)) {
                newlyAddedPoints.add(p)
            }
        }

        if (newlyAddedPoints.isEmpty()) {
            // No new unique points were generated. Target is unreachable.
            return -1L
        }

        // Update state
        currentPoints.addAll(newlyAddedPoints)
    }
}
